module RefModule (  
    input [3:0] A,  
    input [3:0] B,  
    input Cin,  
    output [4:0] Sum  
);  
    wire [3:0] obf_C;  
    assign Sum[0] = A[0] ^ B[0] ^ Cin;  
    assign obf_C[0] = (A[0] & B[0]) | (Cin & (A[0] ^ B[0]));  
    assign Sum[1] = A[1] ^ B[1] ^ obf_C[0];  
    assign obf_C[1] = (A[1] & B[1]) | (obf_C[0] & (A[1] ^ B[1]));  
    assign Sum[2] = A[2] ^ B[2] ^ obf_C[1];  
    assign obf_C[2] = (A[2] & B[2]) | (obf_C[1] & (A[2] ^ B[2]));  
    assign Sum[3] = A[3] ^ B[3] ^ obf_C[2];  
    assign Sum[4] = (A[3] & B[3]) | (obf_C[2] & (A[3] ^ B[3]));  
endmodule
